settings.custom_liquid:
{% if product.metafields.custom.pdf_download %}
<div class="container a_pdf_block">
  <h3>Download</h3>
  <div class="a_pdf_link">
    <p class="pdf-link">
      <img src="https://cdn.shopify.com/s/files/1/0920/9597/1670/files/file.png?v=1752489914?v=1712824203" alt="PDF-Icon" width="16px" height="16px">
      <a href="{{ product.metafields.custom.pdf_download | file_url }}" target="_blank">{{ product.title }} - Aufzuchtshilfe</a>
    </p>
  </div>

  <style>
    .a_pdf_block {
      padding-left: 100px;
    }

    .a_pdf_link a {
      color: red;
      overflow: hidden;
    }

    .pdf-link {
      display: flex;
      align-items: center;
    }

    .pdf-link a {
      padding-left: 8px;
    }
  </style>
</div>
{% endif %}

{% if product.metafields.custom.Pdf-download %}
<div class="container">
<h3>Downloads (Einzel PDF)</h3>
  <div class="a_pdf_link">
    <p class="pdf-link">
      <img src="https://cdn.shopify.com/s/files/1/0616/8923/3452/files/pdf-icon.svg?v=1712824203" alt="PDF-Icon" width="16px" height="16px">
      <a href="{{ product.metafields.custom.bedienungsanleitung | file_url }}" target="_blank">{{ product.title }} - Bedienungsanleitung</a>
    </p>
  </div>

  <style>
    .a_pdf_link a {
      color: black;
      overflow: hidden;
    }

   .pdf-link {
	   display: flex;
	   align-items: center;
	 }

    .pdf-link a {
      padding-left: 8px;
    }
  </style>
</div>
{% endif %}
